+#[derive(Clone, Copy)]
+enum CmpView<'a> {
+    Node(&'a Term),
+    PairTail(&'a [Term]),
+}
+
+/// Structural term order pinned by the equations block (probes p_eqA–p_eqI,
+/// targets contract/mesh):
